import { useEffect } from "react";
import { useLocation, Link } from "wouter";
import { useQuery } from "@tanstack/react-query";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { useAuth } from "@/lib/auth";
import { ThemeToggle } from "@/components/theme-toggle";
import { 
  LogOut, 
  FileText, 
  Clock, 
  CheckCircle, 
  ArrowRight,
  BookOpen,
  Loader2,
  Calendar,
  Library,
  AlertTriangle,
  TrendingUp,
  Bell
} from "lucide-react";
import type { Assignment, Announcement } from "@shared/schema";
import logoPath from "@assets/image_1769457206059.png";

interface EnrichedSubmission {
  id: number;
  assignmentId: number;
  studentId: number;
  status: string;
  submittedAt: string;
  studentName?: string;
  assignmentTitle?: string;
  totalMarks?: number;
}

export default function StudentDashboard() {
  const [, setLocation] = useLocation();
  const { student, logout } = useAuth();

  useEffect(() => {
    if (!student) {
      setLocation("/student/login");
    }
  }, [student, setLocation]);

  const { data: assignments, isLoading: assignmentsLoading } = useQuery<Assignment[]>({
    queryKey: ["/api/assignments", { form: student?.form, studentId: student?.id }],
    enabled: !!student,
  });

  const { data: submissions, isLoading: submissionsLoading } = useQuery<EnrichedSubmission[]>({
    queryKey: ["/api/submissions", { studentId: student?.id }],
    enabled: !!student,
  });

  interface StudentStats {
    completed: number;
    pending: number;
    averageScore: number;
    totalSubmissions: number;
  }

  const { data: statsData, isLoading: statsLoading } = useQuery<{ success: boolean; stats: StudentStats }>({
    queryKey: ["/api/students", student?.id, "stats"],
    enabled: !!student,
  });

  const { data: announcements } = useQuery<Announcement[]>({
    queryKey: ["/api/announcements", { form: student?.form }],
    enabled: !!student,
  });

  const handleLogout = () => {
    logout();
    setLocation("/");
  };

  if (!student) return null;

  const submittedAssignmentIds = new Set(submissions?.map(s => s.assignmentId) || []);
  const pendingAssignments = assignments?.filter(a => !submittedAssignmentIds.has(a.id)) || [];
  const markedSubmissions = submissions?.filter(s => s.status === "MARKED") || [];
  const pendingSubmissions = submissions?.filter(s => s.status === "SUBMITTED") || [];

  const isOverdue = (dueDate: string) => new Date(dueDate) < new Date();
  const isDueSoon = (dueDate: string) => {
    const due = new Date(dueDate);
    const now = new Date();
    const diffDays = (due.getTime() - now.getTime()) / (1000 * 60 * 60 * 24);
    return diffDays <= 2 && diffDays >= 0;
  };

  const getPriorityBadge = (priority: string | null) => {
    switch (priority) {
      case "urgent": return <Badge variant="destructive">Urgent</Badge>;
      case "important": return <Badge className="bg-orange-500">Important</Badge>;
      default: return null;
    }
  };

  return (
    <div className="min-h-screen bg-background">
      <header className="sticky top-0 z-50 w-full border-b bg-background/95 backdrop-blur">
        <div className="container mx-auto flex h-16 items-center justify-between gap-4 px-4">
          <div className="flex items-center gap-3">
            <img src={logoPath} alt="On Point" className="h-10 w-auto" />
            <span className="font-semibold text-primary hidden sm:block">Student Portal</span>
          </div>
          <div className="flex items-center gap-2">
            <span className="text-sm text-muted-foreground hidden md:block">
              {student.fullName} ({student.form})
            </span>
            <ThemeToggle />
            <Button variant="outline" size="sm" onClick={handleLogout} data-testid="button-logout">
              <LogOut className="h-4 w-4 mr-2" />
              Logout
            </Button>
          </div>
        </div>
      </header>

      <main className="container mx-auto px-4 py-8">
        <div className="mb-8">
          <h1 className="text-3xl font-bold mb-2">Welcome, {student.fullName}!</h1>
          <p className="text-muted-foreground">{student.form} - ID: {student.studentId}</p>
        </div>

        <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-4 mb-8">
          <Card>
            <CardHeader className="flex flex-row items-center justify-between gap-2 pb-2">
              <CardTitle className="text-sm font-medium">Available</CardTitle>
              <BookOpen className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">
                {assignmentsLoading ? <Loader2 className="h-6 w-6 animate-spin" /> : pendingAssignments.length}
              </div>
              <p className="text-xs text-muted-foreground">assignments to complete</p>
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="flex flex-row items-center justify-between gap-2 pb-2">
              <CardTitle className="text-sm font-medium">Submitted</CardTitle>
              <Clock className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold text-secondary">
                {submissionsLoading ? <Loader2 className="h-6 w-6 animate-spin" /> : pendingSubmissions.length}
              </div>
              <p className="text-xs text-muted-foreground">awaiting review</p>
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="flex flex-row items-center justify-between gap-2 pb-2">
              <CardTitle className="text-sm font-medium">Marked</CardTitle>
              <CheckCircle className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold text-primary">
                {submissionsLoading ? <Loader2 className="h-6 w-6 animate-spin" /> : markedSubmissions.length}
              </div>
              <p className="text-xs text-muted-foreground">with feedback</p>
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="flex flex-row items-center justify-between gap-2 pb-2">
              <CardTitle className="text-sm font-medium">Average Score</CardTitle>
              <TrendingUp className="h-4 w-4 text-muted-foreground" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold text-primary">
                {statsLoading ? <Loader2 className="h-6 w-6 animate-spin" /> : `${statsData?.stats?.averageScore || 0}%`}
              </div>
              <p className="text-xs text-muted-foreground">across all marked work</p>
            </CardContent>
          </Card>
        </div>

        {announcements && announcements.length > 0 && (
          <Card className="mb-6 border-primary/20">
            <CardHeader className="pb-3">
              <div className="flex items-center gap-2">
                <Bell className="h-5 w-5 text-primary" />
                <CardTitle className="text-lg">Announcements</CardTitle>
              </div>
            </CardHeader>
            <CardContent>
              <div className="space-y-3">
                {announcements.slice(0, 3).map((announcement) => (
                  <div 
                    key={announcement.id} 
                    className={`p-3 rounded-md border ${announcement.priority === 'urgent' ? 'border-destructive/50 bg-destructive/5' : announcement.priority === 'important' ? 'border-orange-500/50 bg-orange-500/5' : ''}`}
                  >
                    <div className="flex items-center gap-2 flex-wrap mb-1">
                      <span className="font-medium">{announcement.title}</span>
                      {getPriorityBadge(announcement.priority)}
                    </div>
                    <p className="text-sm text-muted-foreground">{announcement.content}</p>
                    <p className="text-xs text-muted-foreground mt-2">
                      {new Date(announcement.createdAt).toLocaleDateString()}
                    </p>
                  </div>
                ))}
              </div>
            </CardContent>
          </Card>
        )}

        <div className="mb-6">
          <Link href="/student/resources">
            <Card className="hover-elevate cursor-pointer">
              <CardContent className="flex items-center gap-4 py-6">
                <div className="p-3 rounded-md bg-primary/10">
                  <Library className="h-6 w-6 text-primary" />
                </div>
                <div>
                  <h3 className="font-semibold">Learning Resources</h3>
                  <p className="text-sm text-muted-foreground">Access textbooks, videos, and study materials</p>
                </div>
              </CardContent>
            </Card>
          </Link>
        </div>

        <div className="grid gap-6 lg:grid-cols-2">
          <Card>
            <CardHeader>
              <CardTitle>Available Assignments</CardTitle>
              <CardDescription>Assignments waiting for your submission</CardDescription>
            </CardHeader>
            <CardContent>
              {assignmentsLoading ? (
                <div className="flex items-center justify-center py-8">
                  <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
                </div>
              ) : pendingAssignments.length > 0 ? (
                <div className="space-y-3">
                  {pendingAssignments.map((assignment) => (
                    <Link key={assignment.id} href={`/student/submit/${assignment.id}`}>
                      <div className="flex items-center justify-between p-4 rounded-md border hover-elevate cursor-pointer">
                        <div className="flex items-center gap-3">
                          <FileText className="h-5 w-5 text-primary" />
                          <div>
                            <p className="font-medium">{assignment.title}</p>
                            <div className="flex items-center gap-2 text-sm text-muted-foreground">
                              <span>{assignment.subject.replace('_', ' ')}</span>
                              <span>-</span>
                              <span className={`flex items-center gap-1 ${isOverdue(assignment.dueDate) ? 'text-destructive font-medium' : isDueSoon(assignment.dueDate) ? 'text-orange-500 font-medium' : ''}`}>
                                {isOverdue(assignment.dueDate) ? (
                                  <AlertTriangle className="h-3 w-3" />
                                ) : (
                                  <Calendar className="h-3 w-3" />
                                )}
                                {isOverdue(assignment.dueDate) ? 'OVERDUE' : `Due: ${new Date(assignment.dueDate).toLocaleDateString()}`}
                              </span>
                            </div>
                          </div>
                        </div>
                        <div className="flex items-center gap-2">
                          {isOverdue(assignment.dueDate) && (
                            <Badge variant="destructive">Late</Badge>
                          )}
                          {isDueSoon(assignment.dueDate) && !isOverdue(assignment.dueDate) && (
                            <Badge className="bg-orange-500">Due Soon</Badge>
                          )}
                          <Badge variant="outline">{assignment.totalMarks} marks</Badge>
                          <ArrowRight className="h-4 w-4 text-muted-foreground" />
                        </div>
                      </div>
                    </Link>
                  ))}
                </div>
              ) : (
                <div className="text-center py-8">
                  <CheckCircle className="h-12 w-12 mx-auto text-primary mb-4" />
                  <p className="text-muted-foreground">All caught up! No pending assignments.</p>
                </div>
              )}
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle>Your Results</CardTitle>
              <CardDescription>Marked assignments with feedback</CardDescription>
            </CardHeader>
            <CardContent>
              {submissionsLoading ? (
                <div className="flex items-center justify-center py-8">
                  <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
                </div>
              ) : markedSubmissions.length > 0 ? (
                <div className="space-y-3">
                  {markedSubmissions.map((submission) => (
                    <Link key={submission.id} href={`/student/results/${submission.id}`}>
                      <div className="flex items-center justify-between p-4 rounded-md border hover-elevate cursor-pointer">
                        <div className="flex items-center gap-3">
                          <CheckCircle className="h-5 w-5 text-primary" />
                          <div>
                            <p className="font-medium">{submission.assignmentTitle || 'Assignment'}</p>
                            <p className="text-sm text-muted-foreground">
                              Submitted: {new Date(submission.submittedAt).toLocaleDateString()}
                            </p>
                          </div>
                        </div>
                        <div className="flex items-center gap-2">
                          <Badge variant="default">View Results</Badge>
                          <ArrowRight className="h-4 w-4 text-muted-foreground" />
                        </div>
                      </div>
                    </Link>
                  ))}
                </div>
              ) : pendingSubmissions.length > 0 ? (
                <div className="space-y-3">
                  {pendingSubmissions.map((submission) => (
                    <div key={submission.id} className="flex items-center justify-between p-4 rounded-md border bg-muted/30">
                      <div className="flex items-center gap-3">
                        <Clock className="h-5 w-5 text-secondary" />
                        <div>
                          <p className="font-medium">{submission.assignmentTitle || 'Assignment'}</p>
                          <p className="text-sm text-muted-foreground">
                            Submitted: {new Date(submission.submittedAt).toLocaleDateString()}
                          </p>
                        </div>
                      </div>
                      <Badge variant="secondary">Awaiting Review</Badge>
                    </div>
                  ))}
                </div>
              ) : (
                <div className="text-center py-8">
                  <FileText className="h-12 w-12 mx-auto text-muted-foreground mb-4" />
                  <p className="text-muted-foreground">No results yet. Complete some assignments!</p>
                </div>
              )}
            </CardContent>
          </Card>
        </div>
      </main>
    </div>
  );
}

client/src/pages/student/view-results.ts.content:
import { useEffect } from "react";
import { useLocation, Link, useParams } from "wouter";
import { useQuery } from "@tanstack/react-query";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Progress } from "@/components/ui/progress";
import { useAuth } from "@/lib/auth";
import { ThemeToggle } from "@/components/theme-toggle";
import { ArrowLeft, Loader2, CheckCircle, XCircle, Trophy, MessageSquare } from "lucide-react";
import type { Submission, Assignment, Mark } from "@shared/schema";
import logoPath from "@assets/image_1769457206059.png";

export default function ViewResults() {
  const { id } = useParams<{ id: string }>();
  const [, setLocation] = useLocation();
  const { student } = useAuth();

  useEffect(() => {
    if (!student) {
      setLocation("/student/login");
    }
  }, [student, setLocation]);

  const { data: submissionData, isLoading: submissionLoading } = useQuery<Submission & { assignment?: Assignment }>({
    queryKey: ["/api/submissions", id],
    enabled: !!student && !!id,
  });

  // Use the assignment embedded in the submission response (returned by /api/submissions/:id)
  const submission = submissionData;
  const assignment = submissionData?.assignment;

  const { data: mark } = useQuery<Mark>({
    queryKey: ["/api/marks", id],
    enabled: !!submission && submission.status === "MARKED",
  });

  if (!student) return null;

  const percentage = mark ? Math.round((mark.totalScore / (assignment?.totalMarks || 1)) * 100) : 0;

  const getGradeColor = (pct: number) => {
    if (pct >= 80) return "text-green-600 dark:text-green-400";
    if (pct >= 60) return "text-primary";
    if (pct >= 40) return "text-yellow-600 dark:text-yellow-400";
    return "text-destructive";
  };

  const getGradeLabel = (pct: number) => {
    if (pct >= 80) return "Excellent!";
    if (pct >= 60) return "Good Work!";
    if (pct >= 40) return "Keep Trying!";
    return "Needs Improvement";
  };

  return (
    <div className="min-h-screen bg-background">
      <header className="sticky top-0 z-50 w-full border-b bg-background/95 backdrop-blur">
        <div className="container mx-auto flex h-16 items-center justify-between gap-4 px-4">
          <Link href="/student/dashboard" className="flex items-center gap-2">
            <ArrowLeft className="h-4 w-4" />
            <span className="text-sm">Back to Dashboard</span>
          </Link>
          <div className="flex items-center gap-3">
            <img src={logoPath} alt="On Point" className="h-8 w-auto" />
            <ThemeToggle />
          </div>
        </div>
      </header>

      <main className="container mx-auto px-4 py-8 max-w-3xl">
        {submissionLoading ? (
          <div className="flex items-center justify-center py-16">
            <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
          </div>
        ) : submission && assignment && assignment.questions && mark ? (
          <>
            <Card className="mb-6">
              <CardHeader className="text-center">
                <div className="mx-auto mb-4 flex h-20 w-20 items-center justify-center rounded-full bg-primary/10">
                  <Trophy className={`h-10 w-10 ${getGradeColor(percentage)}`} />
                </div>
                <CardTitle className="text-2xl">{assignment.title}</CardTitle>
                <CardDescription>{assignment.subject} - {assignment.form}</CardDescription>
              </CardHeader>
              <CardContent>
                <div className="text-center mb-6">
                  <div className={`text-5xl font-bold mb-2 ${getGradeColor(percentage)}`}>
                    {mark.totalScore}/{assignment.totalMarks}
                  </div>
                  <p className={`text-lg font-medium ${getGradeColor(percentage)}`}>
                    {getGradeLabel(percentage)}
                  </p>
                  <p className="text-muted-foreground">{percentage}%</p>
                </div>
                <Progress value={percentage} className="h-3" />
              </CardContent>
            </Card>

            {mark.feedback && (
              <Card className="mb-6">
                <CardHeader>
                  <CardTitle className="flex items-center gap-2">
                    <MessageSquare className="h-5 w-5" />
                    Teacher's Feedback
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  <p className="whitespace-pre-wrap">{mark.feedback}</p>
                </CardContent>
              </Card>
            )}

            <div className="space-y-4">
              <h2 className="text-xl font-semibold">Question Results</h2>
              {assignment.questions.map((question, index) => {
                const studentAnswer = submission.answers.find(a => a.questionId === question.id);
                const questionMark = mark.questionMarks.find(qm => qm.questionId === question.id);
                const isCorrect = questionMark && questionMark.score === questionMark.maxScore;
                const questionPct = questionMark ? Math.round((questionMark.score / questionMark.maxScore) * 100) : 0;

                return (
                  <Card key={question.id}>
                    <CardHeader>
                      <div className="flex items-center justify-between flex-wrap gap-2">
                        <div className="flex items-center gap-2">
                          {isCorrect ? (
                            <CheckCircle className="h-5 w-5 text-green-600 dark:text-green-400" />
                          ) : (
                            <XCircle className="h-5 w-5 text-destructive" />
                          )}
                          <CardTitle className="text-lg">Question {index + 1}</CardTitle>
                        </div>
                        <Badge 
                          variant={questionPct >= 60 ? "default" : "secondary"}
                          className={questionPct >= 80 ? "bg-green-600" : ""}
                        >
                          {questionMark?.score || 0}/{question.maxScore}
                        </Badge>
                      </div>
                      <CardDescription className="text-base">
                        {question.questionText}
                      </CardDescription>
                      {question.imageUrls && question.imageUrls.length > 0 && (
                        <div className="flex flex-wrap gap-2 mt-3">
                          {question.imageUrls.map((url, imgIndex) => (
                            <a 
                              key={imgIndex} 
                              href={url} 
                              target="_blank" 
                              rel="noopener noreferrer"
                              className="block"
                            >
                              <img 
                                src={url} 
                                alt={`Question ${index + 1} image ${imgIndex + 1}`}
                                className="max-h-48 rounded-md border object-contain hover:opacity-80 transition-opacity"
                              />
                            </a>
                          ))}
                        </div>
                      )}
                    </CardHeader>
                    <CardContent className="space-y-4">
                      <div className="p-3 bg-muted rounded-md">
                        <p className="text-sm font-medium mb-1">Your Answer:</p>
                        <p className="whitespace-pre-wrap text-sm">
                          {studentAnswer?.answerText || <em className="text-muted-foreground">No answer provided</em>}
                        </p>
                      </div>
                      {questionMark?.feedback && (
                        <div className="p-3 bg-primary/5 rounded-md border-l-4 border-primary">
                          <p className="text-sm font-medium mb-1">Feedback:</p>
                          <p className="text-sm">{questionMark.feedback}</p>
                        </div>
                      )}
                    </CardContent>
                  </Card>
                );
              })}
            </div>
          </>
        ) : submission && submission.status === "SUBMITTED" ? (
          <div className="text-center py-16">
            <div className="mx-auto mb-4 flex h-16 w-16 items-center justify-center rounded-full bg-secondary/10">
              <Loader2 className="h-8 w-8 text-secondary animate-spin" />
            </div>
            <h2 className="text-xl font-semibold mb-2">Awaiting Review</h2>
            <p className="text-muted-foreground">Your submission is being reviewed by your teacher.</p>
          </div>
        ) : (
          <div className="text-center py-16">
            <p className="text-muted-foreground">Results not found</p>
          </div>
        )}
      </main>
    </div>
  );
}

