import { useEffect } from "react";
import { useLocation, Link } from "wouter";
import { useQuery } from "@tanstack/react-query";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { useAuth } from "@/lib/auth";
import { ThemeToggle } from "@/components/theme-toggle";
import { ArrowLeft, Loader2, BarChart3, TrendingUp, Users, BookOpen } from "lucide-react";
import { useState } from "react";
import logoPath from "@assets/image_1769457206059.png";
import {
  ChartContainer,
  ChartTooltip,
  ChartTooltipContent,
  type ChartConfig
} from "@/components/ui/chart";
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  PieChart,
  Pie,
  Cell,
  LineChart,
  Line,
  ResponsiveContainer
} from "recharts";

interface ReportData {
  studentPerformance: Array<{
    studentId: number;
    studentName: string;
    form: string;
    totalAssignments: number;
    submittedCount: number;
    markedCount: number;
    totalScore: number;
    maxPossibleScore: number;
    averagePercentage: number;
  }>;
  subjectPerformance: Array<{
    subject: string;
    averageScore: number;
    totalSubmissions: number;
    totalMarked: number;
  }>;
  formPerformance: Array<{
    form: string;
    averageScore: number;
    studentCount: number;
  }>;
}

const CHART_COLORS = [
  "hsl(224, 65%, 35%)",
  "hsl(0, 75%, 50%)",
  "hsl(142, 76%, 36%)",
  "hsl(38, 92%, 50%)",
  "hsl(262, 83%, 58%)",
  "hsl(199, 89%, 48%)",
];

const chartConfig: ChartConfig = {
  averagePercentage: {
    label: "Average %",
    color: "hsl(224, 65%, 35%)",
  },
  averageScore: {
    label: "Average Score",
    color: "hsl(0, 75%, 50%)",
  },
};

export default function TeacherReports() {
  const [, setLocation] = useLocation();
  const { teacher } = useAuth();
  const [formFilter, setFormFilter] = useState<string>("all");

  useEffect(() => {
    if (!teacher) {
      setLocation("/teacher/login");
    }
  }, [teacher, setLocation]);

  const { data: reportResponse, isLoading } = useQuery<{ success: boolean; data: ReportData }>({
    queryKey: ["/api/reports"],
    enabled: !!teacher,
  });

  const reportData = reportResponse?.data;

  if (!teacher) return null;

  const filteredStudents = reportData?.studentPerformance?.filter(
    s => formFilter === "all" || s.form === formFilter
  ) || [];

  const getPerformanceColor = (pct: number) => {
    if (pct >= 80) return "text-green-600 dark:text-green-400";
    if (pct >= 60) return "text-primary";
    if (pct >= 40) return "text-yellow-600 dark:text-yellow-400";
    return "text-destructive";
  };

  const getPerformanceBadge = (pct: number) => {
    if (pct >= 80) return <Badge className="bg-green-600">Excellent</Badge>;
    if (pct >= 60) return <Badge>Good</Badge>;
    if (pct >= 40) return <Badge variant="secondary">Average</Badge>;
    return <Badge variant="destructive">Needs Help</Badge>;
  };

  return (
    <div className="min-h-screen bg-background">
      <header className="sticky top-0 z-50 w-full border-b bg-background/95 backdrop-blur">
        <div className="container mx-auto flex h-16 items-center justify-between gap-4 px-4">
          <Link href="/teacher/dashboard" className="flex items-center gap-2">
            <ArrowLeft className="h-4 w-4" />
            <span className="text-sm">Back to Dashboard</span>
          </Link>
          <div className="flex items-center gap-3">
            <img src={logoPath} alt="On Point" className="h-8 w-auto" />
            <ThemeToggle />
          </div>
        </div>
      </header>

      <main className="container mx-auto px-4 py-8">
        <div className="mb-6">
          <h1 className="text-3xl font-bold flex items-center gap-2">
            <BarChart3 className="h-8 w-8 text-primary" />
            Performance Reports
          </h1>
          <p className="text-muted-foreground mt-1">
            Track student progress and analyze performance trends
          </p>
        </div>

        {isLoading ? (
          <div className="flex items-center justify-center py-16">
            <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
          </div>
        ) : reportData ? (
          <div className="space-y-6">
            <div className="flex items-center gap-4">
              <Select value={formFilter} onValueChange={setFormFilter}>
                <SelectTrigger className="w-40" data-testid="select-form-filter">
                  <SelectValue placeholder="Filter by Form" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">All Forms</SelectItem>
                  <SelectItem value="Form 1">Form 1</SelectItem>
                  <SelectItem value="Form 2">Form 2</SelectItem>
                </SelectContent>
              </Select>
            </div>

            <div className="grid gap-4 md:grid-cols-3">
              <Card>
                <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2 gap-2">
                  <CardTitle className="text-sm font-medium">Total Students</CardTitle>
                  <Users className="h-4 w-4 text-muted-foreground" />
                </CardHeader>
                <CardContent>
                  <div className="text-2xl font-bold">{filteredStudents.length}</div>
                  <p className="text-xs text-muted-foreground">
                    {formFilter === "all" ? "All forms" : formFilter}
                  </p>
                </CardContent>
              </Card>

              <Card>
                <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2 gap-2">
                  <CardTitle className="text-sm font-medium">Average Score</CardTitle>
                  <TrendingUp className="h-4 w-4 text-muted-foreground" />
                </CardHeader>
                <CardContent>
                  <div className={`text-2xl font-bold ${getPerformanceColor(
                    filteredStudents.length > 0 
                      ? Math.round(filteredStudents.reduce((sum, s) => sum + s.averagePercentage, 0) / filteredStudents.length)
                      : 0
                  )}`}>
                    {filteredStudents.length > 0 
                      ? Math.round(filteredStudents.reduce((sum, s) => sum + s.averagePercentage, 0) / filteredStudents.length)
                      : 0}%
                  </div>
                  <p className="text-xs text-muted-foreground">Class average</p>
                </CardContent>
              </Card>

              <Card>
                <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2 gap-2">
                  <CardTitle className="text-sm font-medium">Subjects</CardTitle>
                  <BookOpen className="h-4 w-4 text-muted-foreground" />
                </CardHeader>
                <CardContent>
                  <div className="text-2xl font-bold">{reportData.subjectPerformance?.length || 0}</div>
                  <p className="text-xs text-muted-foreground">Active subjects</p>
                </CardContent>
              </Card>
            </div>

            <div className="grid gap-6 lg:grid-cols-2">
              <Card>
                <CardHeader>
                  <CardTitle>Student Performance</CardTitle>
                  <CardDescription>Average percentage by student</CardDescription>
                </CardHeader>
                <CardContent>
                  {filteredStudents.length > 0 ? (
                    <ChartContainer config={chartConfig} className="h-[300px]">
                      <BarChart data={filteredStudents.slice(0, 10)} layout="vertical" margin={{ left: 80 }}>
                        <CartesianGrid strokeDasharray="3 3" />
                        <XAxis type="number" domain={[0, 100]} />
                        <YAxis dataKey="studentName" type="category" width={80} tick={{ fontSize: 12 }} />
                        <ChartTooltip content={<ChartTooltipContent />} />
                        <Bar dataKey="averagePercentage" fill="hsl(224, 65%, 35%)" radius={4} />
                      </BarChart>
                    </ChartContainer>
                  ) : (
                    <p className="text-muted-foreground text-center py-8">No student data available</p>
                  )}
                </CardContent>
              </Card>

              <Card>
                <CardHeader>
                  <CardTitle>Subject Performance</CardTitle>
                  <CardDescription>Average score by subject</CardDescription>
                </CardHeader>
                <CardContent>
                  {reportData.subjectPerformance && reportData.subjectPerformance.length > 0 ? (
                    <ChartContainer config={chartConfig} className="h-[300px]">
                      <BarChart data={reportData.subjectPerformance}>
                        <CartesianGrid strokeDasharray="3 3" />
                        <XAxis dataKey="subject" tick={{ fontSize: 10 }} angle={-45} textAnchor="end" height={60} />
                        <YAxis domain={[0, 100]} />
                        <ChartTooltip content={<ChartTooltipContent />} />
                        <Bar dataKey="averageScore" fill="hsl(0, 75%, 50%)" radius={4} />
                      </BarChart>
                    </ChartContainer>
                  ) : (
                    <p className="text-muted-foreground text-center py-8">No subject data available</p>
                  )}
                </CardContent>
              </Card>
            </div>

            <Card>
              <CardHeader>
                <CardTitle>Form Comparison</CardTitle>
                <CardDescription>Performance comparison between forms</CardDescription>
              </CardHeader>
              <CardContent>
                {reportData.formPerformance && reportData.formPerformance.length > 0 ? (
                  <div className="grid gap-4 md:grid-cols-2">
                    {reportData.formPerformance.map((form, index) => (
                      <Card key={form.form} className="border-2">
                        <CardHeader className="pb-2">
                          <CardTitle className="text-lg">{form.form}</CardTitle>
                          <CardDescription>{form.studentCount} students</CardDescription>
                        </CardHeader>
                        <CardContent>
                          <div className={`text-3xl font-bold ${getPerformanceColor(form.averageScore)}`}>
                            {form.averageScore}%
                          </div>
                          <p className="text-sm text-muted-foreground">Average score</p>
                        </CardContent>
                      </Card>
                    ))}
                  </div>
                ) : (
                  <p className="text-muted-foreground text-center py-8">No form data available</p>
                )}
              </CardContent>
            </Card>

            <Card>
              <CardHeader>
                <CardTitle>Student Details</CardTitle>
                <CardDescription>Individual student performance breakdown</CardDescription>
              </CardHeader>
              <CardContent>
                <div className="overflow-x-auto">
                  <table className="w-full text-sm" data-testid="table-student-details">
                    <thead>
                      <tr className="border-b">
                        <th className="text-left py-2 px-2">Student</th>
                        <th className="text-left py-2 px-2">Form</th>
                        <th className="text-center py-2 px-2">Submitted</th>
                        <th className="text-center py-2 px-2">Marked</th>
                        <th className="text-center py-2 px-2">Score</th>
                        <th className="text-center py-2 px-2">Average</th>
                        <th className="text-center py-2 px-2">Status</th>
                      </tr>
                    </thead>
                    <tbody>
                      {filteredStudents.map(student => (
                        <tr key={student.studentId} className="border-b hover-elevate">
                          <td className="py-2 px-2 font-medium">{student.studentName}</td>
                          <td className="py-2 px-2">
                            <Badge variant="outline">{student.form}</Badge>
                          </td>
                          <td className="text-center py-2 px-2">
                            {student.submittedCount}/{student.totalAssignments}
                          </td>
                          <td className="text-center py-2 px-2">{student.markedCount}</td>
                          <td className="text-center py-2 px-2">
                            {student.totalScore}/{student.maxPossibleScore}
                          </td>
                          <td className={`text-center py-2 px-2 font-bold ${getPerformanceColor(student.averagePercentage)}`}>
                            {student.averagePercentage}%
                          </td>
                          <td className="text-center py-2 px-2">
                            {getPerformanceBadge(student.averagePercentage)}
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </CardContent>
            </Card>
          </div>
        ) : (
          <Card>
            <CardContent className="py-8 text-center">
              <p className="text-muted-foreground">No report data available yet.</p>
            </CardContent>
          </Card>
        )}
      </main>
    </div>
  );
}

client/src/pages/student/submit-assignme.content:
import { useState, useEffect } from "react";
import { useLocation, Link, useParams } from "wouter";
import { useQuery } from "@tanstack/react-query";
import { useForm, useFieldArray } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Textarea } from "@/components/ui/textarea";
import { Badge } from "@/components/ui/badge";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { useToast } from "@/hooks/use-toast";
import { useAuth } from "@/lib/auth";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { ThemeToggle } from "@/components/theme-toggle";
import { ArrowLeft, Loader2, Send, Calendar, BookOpen, Edit, AlertCircle } from "lucide-react";
import type { Assignment, Submission } from "@shared/schema";
import logoPath from "@assets/image_1769457206059.png";

const answerSchema = z.object({
  questionId: z.string(),
  answerText: z.string().min(1, "Answer is required"),
});

const submitFormSchema = z.object({
  answers: z.array(answerSchema),
});

type SubmitForm = z.infer<typeof submitFormSchema>;

interface ExistingSubmission extends Submission {
  status: string;
}

export default function SubmitAssignment() {
  const { id } = useParams<{ id: string }>();
  const [, setLocation] = useLocation();
  const { student } = useAuth();
  const { toast } = useToast();
  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    if (!student) {
      setLocation("/student/login");
    }
  }, [student, setLocation]);

  const { data: assignment, isLoading: assignmentLoading } = useQuery<Assignment>({
    queryKey: ["/api/assignments", id],
    enabled: !!student && !!id,
  });

  // Check for existing submission
  const { data: existingSubmissions } = useQuery<ExistingSubmission[]>({
    queryKey: ["/api/submissions", { assignmentId: id, studentId: student?.id }],
    enabled: !!student && !!id,
  });

  const existingSubmission = existingSubmissions?.[0];
  const isEditing = !!existingSubmission;
  const isMarked = existingSubmission?.status === "MARKED";

  // Check deadline
  const isDeadlinePassed = assignment ? new Date() > new Date(assignment.dueDate) : false;

  // Check for extended deadline for this student
  const hasExtension = assignment?.extendedDeadlines?.find(e => e.studentId === student?.id);
  const effectiveDeadlinePassed = hasExtension 
    ? new Date() > new Date(hasExtension.newDueDate)
    : isDeadlinePassed;

  const canEdit = isEditing && !isMarked && !effectiveDeadlinePassed;

  const form = useForm<SubmitForm>({
    resolver: zodResolver(submitFormSchema),
    defaultValues: {
      answers: [],
    },
  });

  useEffect(() => {
    if (assignment) {
      const answers = assignment.questions.map((q) => {
        // Load existing answer if editing
        const existingAnswer = existingSubmission?.answers?.find(a => a.questionId === q.id);
        return {
          questionId: q.id,
          answerText: existingAnswer?.answerText || "",
        };
      });
      form.reset({ answers });
    }
  }, [assignment, existingSubmission, form]);

  async function onSubmit(values: SubmitForm) {
    if (!student || !assignment) return;

    setIsLoading(true);
    try {
      let response;

      if (isEditing && existingSubmission) {
        // Update existing submission
        response = await apiRequest("PUT", `/api/submissions/${existingSubmission.id}`, {
          answers: values.answers,
        });
      } else {
        // Create new submission
        response = await apiRequest("POST", "/api/submissions", {
          assignmentId: assignment.id,
          studentId: student.id,
          answers: values.answers,
        });
      }

      const data = await response.json();

      if (data.success) {
        queryClient.invalidateQueries({ queryKey: ["/api/submissions"] });
        queryClient.invalidateQueries({ queryKey: ["/api/assignments"] });
        toast({
          title: isEditing ? "Updated successfully!" : "Submitted successfully!",
          description: isEditing ? "Your changes have been saved." : "Your work has been submitted for review.",
        });
        setLocation("/student/dashboard");
      } else {
        toast({
          title: "Error",
          description: data.message || "Failed to submit",
          variant: "destructive",
        });
      }
    } catch (error) {
      toast({
        title: "Error",
        description: "Failed to submit. Please try again.",
        variant: "destructive",
      });
    } finally {
      setIsLoading(false);
    }
  }

  if (!student) return null;

  return (
    <div className="min-h-screen bg-background">
      <header className="sticky top-0 z-50 w-full border-b bg-background/95 backdrop-blur">
        <div className="container mx-auto flex h-16 items-center justify-between gap-4 px-4">
          <Link href="/student/dashboard" className="flex items-center gap-2">
            <ArrowLeft className="h-4 w-4" />
            <span className="text-sm">Back to Dashboard</span>
          </Link>
          <div className="flex items-center gap-3">
            <img src={logoPath} alt="On Point" className="h-8 w-auto" />
            <ThemeToggle />
          </div>
        </div>
      </header>

      <main className="container mx-auto px-4 py-8 max-w-3xl">
        {assignmentLoading ? (
          <div className="flex items-center justify-center py-16">
            <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
          </div>
        ) : assignment ? (
          <>
            <Card className="mb-6">
              <CardHeader>
                <div className="flex items-center gap-3 mb-2 flex-wrap">
                  <CardTitle className="text-2xl">{assignment.title}</CardTitle>
                  <Badge variant="outline">{assignment.subject}</Badge>
                </div>
                <CardDescription className="flex items-center gap-4 flex-wrap">
                  <span className="flex items-center gap-1">
                    <Calendar className="h-4 w-4" />
                    Due: {new Date(assignment.dueDate).toLocaleDateString()}
                  </span>
                  <span className="flex items-center gap-1">
                    <BookOpen className="h-4 w-4" />
                    {assignment.totalMarks} marks
                  </span>
                </CardDescription>
              </CardHeader>
              <CardContent>
                <div className="p-4 bg-muted rounded-md">
                  <h3 className="font-semibold mb-2">Instructions</h3>
                  <p className="whitespace-pre-wrap text-sm">{assignment.instructions}</p>
                </div>
              </CardContent>
            </Card>

            <Form {...form}>
              <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6">
                {assignment.questions.map((question, index) => (
                  <Card key={question.id}>
                    <CardHeader>
                      <div className="flex items-center justify-between flex-wrap gap-2">
                        <CardTitle className="text-lg">Question {index + 1}</CardTitle>
                        <Badge variant="secondary">{question.maxScore} marks</Badge>
                      </div>
                      <CardDescription className="text-base text-foreground">
                        {question.questionText}
                      </CardDescription>
                      {question.imageUrls && question.imageUrls.length > 0 && (
                        <div className="flex flex-wrap gap-2 mt-3">
                          {question.imageUrls.map((url, imgIndex) => (
                            <a 
                              key={imgIndex} 
                              href={url} 
                              target="_blank" 
                              rel="noopener noreferrer"
                              className="block"
                            >
                              <img 
                                src={url} 
                                alt={`Question ${index + 1} image ${imgIndex + 1}`}
                                className="max-h-48 rounded-md border object-contain hover:opacity-80 transition-opacity"
                              />
                            </a>
                          ))}
                        </div>
                      )}
                    </CardHeader>
                    <CardContent>
                      <FormField
                        control={form.control}
                        name={`answers.${index}.answerText`}
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel>Your Answer</FormLabel>
                            <FormControl>
                              <Textarea
                                placeholder="Type your answer here..."
                                className="min-h-[120px]"
                                data-testid={`textarea-answer-${index}`}
                                {...field}
                              />
                            </FormControl>
                            <FormMessage />
                          </FormItem>
                        )}
                      />
                    </CardContent>
                  </Card>
                ))}

                {isEditing && (
                  <Alert className="mb-4">
                    <Edit className="h-4 w-4" />
                    <AlertDescription>
                      {isMarked 
                        ? "This assignment has been marked. You can no longer make changes."
                        : effectiveDeadlinePassed
                          ? "The deadline has passed. You can no longer make changes."
                          : "You've already submitted this assignment. You can update your answers until the deadline or until your teacher marks it."}
                    </AlertDescription>
                  </Alert>
                )}

                <Button 
                  type="submit" 
                  className="w-full" 
                  size="lg"
                  disabled={isLoading || (isEditing && !canEdit)}
                  data-testid="button-submit"
                >
                  {isLoading ? (
                    <Loader2 className="h-4 w-4 animate-spin mr-2" />
                  ) : isEditing ? (
                    <Edit className="h-4 w-4 mr-2" />
                  ) : (
                    <Send className="h-4 w-4 mr-2" />
                  )}
                  {isEditing ? "Update Submission" : "Submit Assignment"}
                </Button>
              </form>
            </Form>
          </>
        ) : (
          <div className="text-center py-16">
            <p className="text-muted-foreground">Assignment not found</p>
          </div>
        )}
      </main>
    </div>
  );
}

shared/schema.ts.content:
import { pgTable, text, serial, integer, timestamp, jsonb, boolean } from "drizzle-orm/pg-core";
import { relations } from "drizzle-orm";
import { createInsertSchema } from "drizzle-zod";
import { z } from "zod";

// Enums
export const subjectEnum = z.enum(["MATHS", "ENGLISH", "PHYSICS", "CHEMISTRY", "BIOLOGY", "ECONOMICS", "BUSINESS_STUDIES", "GEOGRAPHY", "COMPUTER_SCIENCE", "HISTORY", "ACCOUNTING"]);
export type Subject = z.infer<typeof subjectEnum>;

export const formEnum = z.enum(["Form 1", "Form 2"]);
export type Form = z.infer<typeof formEnum>;

export const submissionStatusEnum = z.enum(["SUBMITTED", "MARKED"]);
export type SubmissionStatus = z.infer<typeof submissionStatusEnum>;

export const resourceTypeEnum = z.enum(["TEXTBOOK", "YOUTUBE", "LESSON_PLAN", "OTHER"]);
export type ResourceType = z.infer<typeof resourceTypeEnum>;

// Teachers table
export const teachers = pgTable("teachers", {
  id: serial("id").primaryKey(),
  fullName: text("full_name").notNull(),
  email: text("email").notNull().unique(),
  password: text("password").notNull(),
  role: text("role").notNull().default("teacher"), // Role for access control
  createdAt: timestamp("created_at").defaultNow().notNull(),
});

export const teachersRelations = relations(teachers, ({ many }) => ({
  assignments: many(assignments),
  marks: many(marks),
  resources: many(resources),
}));

export const insertTeacherSchema = createInsertSchema(teachers).omit({ id: true, createdAt: true });
export type Teacher = typeof teachers.$inferSelect;
export type InsertTeacher = z.infer<typeof insertTeacherSchema>;

// Role enum for access control
export const roleEnum = z.enum(["admin", "teacher", "student"]);
export type Role = z.infer<typeof roleEnum>;

// Students table
export const students = pgTable("students", {
  id: serial("id").primaryKey(),
  studentId: text("student_id").notNull().unique(), // e.g., F1-001
  fullName: text("full_name").notNull(),
  gender: text("gender").notNull(), // Male/Female
  form: text("form").notNull(), // Form 1, Form 2
  password: text("password"), // Personalized password - set by student on first login
  role: text("role").notNull().default("student"), // Role for access control
  createdAt: timestamp("created_at").defaultNow().notNull(),
});

export const studentsRelations = relations(students, ({ many }) => ({
  submissions: many(submissions),
}));

export const insertStudentSchema = createInsertSchema(students).omit({ id: true, createdAt: true });
export type Student = typeof students.$inferSelect;
export type InsertStudent = z.infer<typeof insertStudentSchema>;

// Assignments table
export const assignments = pgTable("assignments", {
  id: serial("id").primaryKey(),
  subject: text("subject").notNull(),
  topic: text("topic"), // Optional topic within subject (e.g., "Algebra" under Maths)
  form: text("form").notNull(), // Form 1, Form 2
  title: text("title").notNull(),
  instructions: text("instructions").notNull(),
  questions: jsonb("questions").$type<Array<{
    id: string;
    questionText: string;
    maxScore: number;
    imageUrls?: string[];
  }>>().notNull(),
  attachments: jsonb("attachments").$type<Array<{
    name: string;
    url: string;
    type: string;
  }>>().default([]),
  dueDate: text("due_date").notNull(),
  totalMarks: integer("total_marks").notNull(),
  targetStudentIds: jsonb("target_student_ids").$type<number[]>().default([]), // For tailored homework
  extendedDeadlines: jsonb("extended_deadlines").$type<Array<{
    studentId: number;
    newDueDate: string;
    reason?: string;
  }>>().default([]), // Per-student deadline extensions
  createdAt: timestamp("created_at").defaultNow().notNull(),
  createdById: integer("created_by_id").notNull().references(() => teachers.id),
});

export const assignmentsRelations = relations(assignments, ({ one, many }) => ({
  createdBy: one(teachers, {
    fields: [assignments.createdById],
    references: [teachers.id],
  }),
  submissions: many(submissions),
}));

export const insertAssignmentSchema = createInsertSchema(assignments).omit({ id: true, createdAt: true });
export type Assignment = typeof assignments.$inferSelect;
export type InsertAssignment = z.infer<typeof insertAssignmentSchema>;

// Submissions table
export const submissions = pgTable("submissions", {
  id: serial("id").primaryKey(),
  assignmentId: integer("assignment_id").notNull().references(() => assignments.id),
  studentId: integer("student_id").notNull().references(() => students.id),
  submittedAt: timestamp("submitted_at").defaultNow().notNull(),
  status: text("status").notNull().default("SUBMITTED"),
  answers: jsonb("answers").$type<Array<{
    questionId: string;
    answerText: string;
    imageUrls?: string[];
  }>>().notNull(),
  aiAnalysis: jsonb("ai_analysis").$type<{
    overallScore: number;
    flags: string[];
    details: string;
  } | null>().default(null),
});

export const submissionsRelations = relations(submissions, ({ one }) => ({
  assignment: one(assignments, {
    fields: [submissions.assignmentId],
    references: [assignments.id],
  }),
  student: one(students, {
    fields: [submissions.studentId],
    references: [students.id],
  }),
}));

export const insertSubmissionSchema = createInsertSchema(submissions).omit({ id: true, submittedAt: true, status: true, aiAnalysis: true });
export type Submission = typeof submissions.$inferSelect;
export type InsertSubmission = z.infer<typeof insertSubmissionSchema>;

// Marks table
export const marks = pgTable("marks", {
  id: serial("id").primaryKey(),
  submissionId: integer("submission_id").notNull().references(() => submissions.id),
  totalScore: integer("total_score").notNull(),
  feedback: text("feedback"),
  markedAt: timestamp("marked_at").defaultNow().notNull(),
  markedById: integer("marked_by_id").notNull().references(() => teachers.id),
  questionMarks: jsonb("question_marks").$type<Array<{
    questionId: string;
    score: number;
    maxScore: number;
    feedback?: string;
  }>>().notNull(),
});

export const marksRelations = relations(marks, ({ one }) => ({
  submission: one(submissions, {
    fields: [marks.submissionId],
    references: [submissions.id],
  }),
  markedBy: one(teachers, {
    fields: [marks.markedById],
    references: [teachers.id],
  }),
}));

export const insertMarkSchema = createInsertSchema(marks).omit({ id: true, markedAt: true });
export type Mark = typeof marks.$inferSelect;
export type InsertMark = z.infer<typeof insertMarkSchema>;

// Resources table (textbooks, YouTube links, lesson plans)
export const resources = pgTable("resources", {
  id: serial("id").primaryKey(),
  title: text("title").notNull(),
  description: text("description"),
  type: text("type").notNull(), // TEXTBOOK, YOUTUBE, LESSON_PLAN, OTHER
  url: text("url"), // For links
  fileUrl: text("file_url"), // For uploaded files
  subject: text("subject"),
  form: text("form"), // Form 1, Form 2, or null for all
  isTeacherOnly: boolean("is_teacher_only").default(false),
  createdAt: timestamp("created_at").defaultNow().notNull(),
  createdById: integer("created_by_id").notNull().references(() => teachers.id),
});

export const resourcesRelations = relations(resources, ({ one }) => ({
  createdBy: one(teachers, {
    fields: [resources.createdById],
    references: [teachers.id],
  }),
}));

export const insertResourceSchema = createInsertSchema(resources).omit({ id: true, createdAt: true });
export type Resource = typeof resources.$inferSelect;
export type InsertResource = z.infer<typeof insertResourceSchema>;

// Announcements table
export const announcements = pgTable("announcements", {
  id: serial("id").primaryKey(),
  title: text("title").notNull(),
  content: text("content").notNull(),
  form: text("form"), // Form 1, Form 2, or null for all
  priority: text("priority").default("normal"), // normal, important, urgent
  createdAt: timestamp("created_at").defaultNow().notNull(),
  expiresAt: timestamp("expires_at"),
  createdById: integer("created_by_id").notNull().references(() => teachers.id),
});

export const announcementsRelations = relations(announcements, ({ one }) => ({
  createdBy: one(teachers, {
    fields: [announcements.createdById],
    references: [teachers.id],
  }),
}));

export const insertAnnouncementSchema = createInsertSchema(announcements).omit({ id: true, createdAt: true });
export type Announcement = typeof announcements.$inferSelect;
export type InsertAnnouncement = z.infer<typeof insertAnnouncementSchema>;

// Login schemas
export const teacherLoginSchema = z.object({
  email: z.string().email("Valid email is required"),
  password: z.string().min(1, "Password is required"),
});
export type TeacherLogin = z.infer<typeof teacherLoginSchema>;

export const studentLoginSchema = z.object({
  fullName: z.string().min(1, "Your name is required"),
  password: z.string().min(6, "Password must be at least 6 characters"),
});
export type StudentLogin = z.infer<typeof studentLoginSchema>;

// Master password for admin access
export const MASTER_PASSWORD = "onpoint_admin_2024";

